head.script:
scwin.initData = {
	"isValidate" : false,
	"isSaveProcess" : false,
	"acbMappingCdObj" : {
		"elcpwstnNm" : "cmmnCd"
	},
	"acbMappingNmObj" : {
		"setcscNm" : "upperCmmnCdNm2",
		"deptNm" : "upperCmmnCdNm3"
	},
	"valInfo" : [
		{id : "elcpwstnNm", maxLength : 40, mandatory : true},
		{id : "mrnrNm", maxByteLength : 100, mandatory : true},
		{id : "eqpCpcty", maxByteLength : 22, number : true},
		{id : "eqpDivInfo", maxByteLength : 100},
		{id : "mnfctrYm", maxByteLength : 6, number : true, dateFunc : ecsLib.validatorYearMonth},
		{id : "erorExamHistYm", maxByteLength : 6, number : true, dateFunc : ecsLib.validatorYearMonth},
		{id : "erorExamPlanYm", maxByteLength : 6, number : true, dateFunc : ecsLib.validatorYearMonth},
		{id : "nationAthrzHistYm", maxByteLength : 6, number : true, dateFunc : ecsLib.validatorYearMonth},
		{id : "nationAthrzPlanYm", maxByteLength : 6, number : true, dateFunc : ecsLib.validatorYearMonth},
		{id : "cdmExamCyclePd", maxByteLength : 100},
		{id : "cdmGrpId", maxByteLength : 40},
		{id : "rmCtnt", maxByteLength : 4000}
	]
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSME3100000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 초기 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("deptCd", "ALL");
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");
	var ecsElcpwstnDivCd = dmaSearchParam.get("elcpwstnCd");

	var queryString = `?ecsChrgDeptId=${ecsChrgDeptId}`;
	queryString += `&ecsElcpwstnDivCd=${ecsElcpwstnDivCd}`;

	var option = {
		action : "me/elyrseltengmsrins/retrieve-elyrs-elteng-msrins.do"
			+ queryString,
		method : "get",
		resData : dltElyrsEltengMsrinsList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param <Object>
 * @return
 */
scwin.inqireCallback = function() {
	spnTotalRow.setValue(dltElyrsEltengMsrinsList.getRowCount());
	var mandatoryList = scwin.initData.valInfo.filter(obj => obj.mandatory);
	for (var i = 0; i < dltElyrsEltengMsrinsList.getRowCount(); i++) {
		mandatoryList.forEach(obj => {
			grdElyrsEltengMsrinsList.setCellReadOnly(i, obj.id, true);
		});
	}

	var nowYm = $p.getCurrentServerDate("yyyy");
	dltElyrsEltengMsrinsList.getAllJSON().forEach((obj, i) => {
		// 오차시험/국가검정 계획 년월 올해면 셀 폰트,배경 색 변경 _240215
		if (obj.erorExamPlanYm != "" && obj.erorExamPlanYm.startsWith(nowYm)) {
			grdElyrsEltengMsrinsList.setCellBackgroundColor(i, "erorExamPlanYm", "#F5F5FF");
			grdElyrsEltengMsrinsList.setCellColor(i, "erorExamPlanYm", "#0000FF");
		} else {
			//grdElyrsEltengMsrinsList.setCellBackgroundColor(i, "erorExamPlanYm", "");
			//grdElyrsEltengMsrinsList.setCellColor(i, "erorExamPlanYm", "");
		}
		if (obj.nationAthrzPlanYm != "" && obj.nationAthrzPlanYm.startsWith(nowYm)) {
			grdElyrsEltengMsrinsList.setCellBackgroundColor(i, "nationAthrzPlanYm", "#F5F5FF");
			grdElyrsEltengMsrinsList.setCellColor(i, "nationAthrzPlanYm", "#0000FF");
		} else {
			//grdElyrsEltengMsrinsList.setCellBackgroundColor(i, "nationAthrzPlanYm", "");
			//grdElyrsEltengMsrinsList.setCellColor(i, "nationAthrzPlanYm", "");
		}
	});
	scwin.initData.isValidate = false;
};

/**
 * 그리드뷰 행을 추가한다.
 * @param
 * @return
 */
scwin.btnAddRow_onclick = function() {
	var newIndex = dltElyrsEltengMsrinsList.insertRow();

	grdElyrsEltengMsrinsList.setFocusedCell(newIndex, "elcpwstnNm", true);
};

/**
 * 그리드뷰 행을 삭제한다.
 * @param
 * @return
 */
scwin.btnDelRow_onclick = function() {
	var rowIndexList = grdElyrsEltengMsrinsList.getAllFocusedRowIndex();

	dltElyrsEltengMsrinsList.removeRows(rowIndexList);
};

/**
 * 그리드뷰의 내용을 검증한다.
 * @param
 * @return
 */
scwin.btnValidate_onclick = function(confirmValue) {
	if (confirmValue == true || confirmValue == undefined) {
		if (dltElyrsEltengMsrinsList.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		if (utilLib.validateGridView(grdElyrsEltengMsrinsList, scwin.initData.valInfo)) {
			var columnList = scwin.initData.valInfo.filter(obj => obj.mandatory).flatMap(obj => obj.id.replace("elcpwstnNm", "ecsElcpwstnDivCd"));
			if (ecsLib.gridViewPkDuplicationCheck(grdElyrsEltengMsrinsList, dltElyrsEltengMsrinsList, columnList)) {
				// 중복 데이터가 있습니다.
				return;
			}

			if (ecsLib.validateGridViewAcb(grdElyrsEltengMsrinsList, dltAutoCondition2, scwin.initData.acbMappingCdObj, scwin.initData.acbMappingNmObj)) {
				// 해당하는 {컬럼명}이(가) 존재하지 않습니다.
				return;
			}
			scwin.initData.isValidate = true;
			if (scwin.initData.isSaveProcess) {
				scwin.initData.isSaveProcess = false;
				scwin.btnSave_onclick();
			} else {
				// 데이터 검증이 완료되었습니다.
				comLib.alert($p, utilLib.getMessage("ECS.INFO.00102"));
			}
		}
	} else {
		scwin.initData.isSaveProcess = false;
	}
};

/**
 * 그리드뷰의 내용을 수정/저장한다.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	scwin.initData.isSaveProcess = false;
	if (dltElyrsEltengMsrinsList.getModifiedData() == "") {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		return;
	}

	if (scwin.initData.isValidate) {
		var addCount = 0;
		var modifyCount = 0;
		var delCount = 0;
		dltElyrsEltengMsrinsList.getModifiedJSON().forEach(obj => {
			var rowStatus = obj.rowStatus;
			switch(rowStatus) {
				case "C":
					// 추가
					addCount++;
					break;
				case "U":
					// 수정
					modifyCount++;
					break;
				case "E":
					// 삭제
					delCount++;
					break;
				default:
					break;
			}
		});
		var extendMsg = ecsLib.extendCustomSaveMsg(addCount, modifyCount, delCount);
		// 변경된 내역이 있습니다.\n저장 하시겠습니까? \n수정사유를 입력하세요.
		ecsLib.saveRsn($p, `${dltElyrsEltengMsrinsList.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00239")[0] + extendMsg, "scwin.saveConfirmCallback");
	} else {
		scwin.initData.isSaveProcess = true;
		// 데이터 검증 후 저장 가능합니다.\n검증하시겠습니까?
		comLib.confirm($p, utilLib.getMessage("ECS.INFO.00101"), "scwin.btnValidate_onclick", true);
		return;
	}
};

/**
 * 수정/저장 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var requestData = {};
	requestData.dltElyrsEltengMsrinsList = dltElyrsEltengMsrinsList.getModifiedJSON();

	// 발전소네임이 코드로 나와서 다시 네임으로 재설정_231207
	requestData.dltElyrsEltengMsrinsList.forEach(obj => {
		var elcpwstnNm = dltAutoCondition2.getAllJSON().find(search => search.cmmnCd == obj.elcpwstnNm);
		var ecsElcpwstnDivCd = dltAutoCondition2.getAllJSON().find(search => search.cmmnCd == obj.elcpwstnNm);

		if (elcpwstnNm) {
			obj.elcpwstnNm = elcpwstnNm.cmmnCdNm;
			obj.ecsElcpwstnDivCd = ecsElcpwstnDivCd.cmmnCd;
		} 
	});

	var option = {
		action : "me/elyrseltengmsrins/process-elyrs-elteng-msrins.do",
		reqData : requestData,
		success : "scwin.saveConfirmSuccessCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 수정/저장 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.saveConfirmSuccessCallback = function(resBody) {
	comLib.alert($p, resBody.message.code_name);

	scwin.btnInqire_onclick();
};

/**
 * 작업중이던 내용을 취소한다.
 * @param
 * @return
 */
scwin.btnCancl_onclick = function() {
	scwin.btnInqire_onclick();
};

/**
 * 데이터컬렉션의 추가/변경/삭제 시 이벤트
 * @param
 * @return
 */
scwin.dltElyrsEltengMsrinsList_ondatachange = function(info) {
	scwin.initData.isValidate = false;
};

/**
 * 조회박스 선택별 값을 세팅한다.
 * @param info
 * @return
 */
scwin.acbDept_onviewchange = function(info) {
	var ecsChrgDeptId = info.newValue;
	dmaSearchParam.set("deptCd", ecsChrgDeptId);

	var queryString = `&ecsChrgDeptId=${ecsChrgDeptId}`;
	var option = {
		action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=elcpwstnKepco" +
			queryString,
		method : "get",
		resData : dltAutoCondition2,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

scwin.acbElcpwstn_onviewchange = function(info) {
	dmaSearchParam.set("elcpwstnCd", info.newValue);
};

scwin.grdElyrsEltengMsrinsList_onafteredit = function(row,col,value) {
	ecsLib.updateGridViewFontColor(grdElyrsEltengMsrinsList, row, col);
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm = spnSubTitle.getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 14,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	// 데이터가 없어도 탬플릿만 다운받을 수 있게 comLib.downloadExcel 말고 grdID.advancedExcelDownload 적용_231113
	var options = {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		startRowIndex : 1,
		startColumnIndex : 0,
		rowHeight : 40,
		useStyle: true,
		useDataFormat: true,
		applyDataFormat : true
	};
	grdElyrsEltengMsrinsList.advancedExcelDownload(options, infoArr);
};

/**
 * 엑셀의 내용을 그리드에 업로드 한다.
 * @return
 */
scwin.btnUploadExcel_onclick = function() {
	var options = {
		type : 1,
		headerExist : 1,
		startRowIndex : 1,
		startColumnIndex : 0,
		endColumnIndex : 14,
		sheetNo : 0,
		append : 0,
		status: "C",
		useMaxByteLength : true
	};
	comLib.uploadExcel(grdElyrsEltengMsrinsList, options);
};

/**
 * 엑셀 내용을 그리드에 저장한다.
 * @return
 */
scwin.grdElyrsEltengMsrinsList_onfilereadend = function(value) {
	var dltData = dltElyrsEltengMsrinsList.getAllJSON();
	var dltAuto2 = dltAutoCondition2.getAllJSON();
	// set JSON
	for (var idx = 0; idx < dltData.length; idx++) {
		var elcpwstnNm = (dltAuto2.find(obj => obj.cmmnCd == dltData[idx].elcpwstnNm) || 0).cmmnCd;
		dltElyrsEltengMsrinsList.setCellData(idx, "elcpwstnNm", elcpwstnNm);
		if (dltElyrsEltengMsrinsList.getCellData(idx, "eqpCpcty") == "-") {
			dltElyrsEltengMsrinsList.setCellData(idx, "eqpCpcty", "");
		}
	}
};
